def check_bounds(x, B=100, v=None):
    """Checks whether one of the variables in the array x is out of bounds

    :param [float] x: array of parameters
    :param float B: maximum value of all parameters
    :param [str] v: list of corresponding names, if available
    :return: None
    """
    for i in range(len(x)):
        if np.abs(x[i]) > B:
            if v != None:
                S = 'parameter {:s} = {:g} is out of bounds!'.format(v[i], x[i])
            else:
                S = 'parameter no {:d}  = {:g} is out of bounds!'.format(i+1, x[i])
            raise pyqcm.OutOfBoundsError(S)

#---------------------------------------------------------------------------------------------------
# optimization of the bath parameters

def optimize(F, x, method='Nelder-Mead', initial_step=0.1, accur = 1e-4, accur_dist = 1e-8, maxfev=5000000):
    """

    :param F: function to be optimized
    :param (float) x: array of variables
    :param str method: method to use, as used in scipy.optimize.minimize()
    :param float initial_step: initial step in the minimization procedure
    :param float accur: requested accuracy in the parameters
    :param float accur_dist: requested accuracy in the distance function

    """
    import scipy.optimize

    displaymin = False
    nvar = len(x)
    if method == 'Nelder-Mead':
        initial_simplex = np.zeros((nvar + 1, nvar))
        for i in range(nvar + 1):
            initial_simplex[i, :] = x
        for i in range(nvar):
            initial_simplex[i + 1, i] += initial_step
        sol = scipy.optimize.minimize(F, x, method='Nelder-Mead', options={'disp':displaymin, 'maxfev':maxfev, 'xatol': accur, 'fatol': accur_dist, 'initial_simplex': initial_simplex, 'adaptive': True})
        iter_done = sol.nit

    elif method == 'Powell':
        sol = scipy.optimize.minimize(F, x, method='Powell', tol = accur)
        iter_done = sol.nit

    elif method == 'CG':
        sol = scipy.optimize.minimize(F, x, method='CG', jac=False, tol = accur, options={'gtol':1e-6, 'eps':1e-6})
        iter_done = sol.nit

    elif method == 'BFGS':
        sol = scipy.optimize.minimize(F, x, method='BFGS', jac=False, tol = accur, options={'eps':accur})
        iter_done = sol.nit

    elif method == 'COBYLA':
        sol = scipy.optimize.minimize(F, x, method='COBYLA', options={'disp':displaymin, 'rhobeg':initial_step, 'maxiter':maxfev, 'tol': accur_dist})
        iter_done = sol.nfev

    elif method == 'ANNEAL':
        sol = scipy.optimize.basinhopping(F, x, minimizer_kwargs = {'method':'COBYLA', 'options':{'disp':displaymin, 'rhobeg':initial_step, 'maxiter':maxfev, 'tol': accur_dist}})
        iter_done = sol.nfev

    else:
        raise ValueError(f'unknown method specified for minimization: {method}')

    if not sol.success:
        print(sol.message)
        raise pyqcm.MinimizationError()

    return sol, iter_done

def optimize_skl(F, x0, bounds, n_calls=10000):
    """
    Optimizes the CDMFT distance function using Bayesian Optimization.

    :param F: Function to be optimized (e.g., the distance function in CDMFT computation)
    :param x0: List of initial guesses for the parameters.
    :param bounds: List of tuples defining the bounds for the parameters.
    :param method: The optimization method; defaults to 'gp_minimize' from skopt.
    :param n_calls: Total number of evaluations of the function.
    :param n_random_starts: Number of evaluations with random points before approximating it with `gp_minimize`.
    :param acq_func: Acquisition function to be used by the optimizer.

    Returns the result object from the Bayesian optimizer.
    """
    from skopt import gp_minimize, gbrt_minimize, dummy_minimize, forest_minimize
    from skopt.space import Real

    # Translating user bounds into what skopt understands.
    dimensions = [Real(low=low, high=high) for (low, high) in bounds]

    # Performing the optimization using Gaussian Process
    result = gp_minimize(F, dimensions, x0=list(x0), n_calls=n_calls)

    return result, result.x_iters
